{"content":"package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowLintTest : TestBase() {

    @Test
    fun testToListUsesDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 10)
        sharedFlow.emit(1)
        sharedFlow.emit(2)

        val acc = ArrayList<Int>()
        acc.add(0) // Pre-fill to verify we are appending to the same list

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
             // This uses the deprecated extension method in Lint.kt
            sharedFlow.toList(acc)
        }

        yield()
        sharedFlow.emit(3)
        yield()

        job.cancel()

        // With the bug, acc only contains [0]
        // With the fix, acc should contain [0, 1, 2, 3]
        assertEquals(listOf(0, 1, 2, 3), acc)
    }

    @Test
    fun testToSetUsesDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 10)
        sharedFlow.emit(1)
        sharedFlow.emit(2)

        val acc = LinkedHashSet<Int>()
        acc.add(0)

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toSet(acc)
        }

        yield()
        sharedFlow.emit(3)
        yield()

        job.cancel()

        assertEquals(setOf(0, 1, 2, 3), acc)
    }
}
